parameters.query:
SELECT EXISTS(
  SELECT 1 FROM exercise_plans
  WHERE user_id = $1
    AND is_active = true
    AND plan_json::jsonb @> jsonb_build_object('day_of_week', to_char($2::date, 'FMDay'))
) AS has_workout;

parameters.jsCode:
const profile = $('Load User Profile').first().json;
const recentPlans = $('Get Recent Meals').all().map(i => i.json).filter(r => r && r.plan_json);
const yesterdayRaw = $('Get Yesterday Intake').first()?.json || null;
const weeklyAvgRaw = $('Get Weekly Average').first()?.json || null;
const hasWorkout = $('Check Workout Day').first()?.json?.has_workout || false;
const trigger = $('Execute Workflow Trigger').first().json;
const planDate = trigger.planDate;
const userId = trigger.userId;

// Recent meals summary (avoid repetition)
let recentMeals = '';
for (const plan of recentPlans) {
  const p = typeof plan.plan_json === 'string' ? JSON.parse(plan.plan_json) : plan.plan_json;
  const mealNames = (p.meals || []).map(m => m.name).join(', ');
  recentMeals += `${plan.plan_date}: ${mealNames}\n`;
}

// Day of week
const dayNames = ['domingo','lunes','martes','miercoles','jueves','viernes','sabado'];
const dateObj = new Date(planDate + 'T12:00:00');
const dayOfWeek = dayNames[dateObj.getDay()];
const isWeekend = dateObj.getDay() === 0 || dateObj.getDay() === 6;

// Yesterday intake (only if user logged meals)
const yesterdayIntake = (yesterdayRaw?.meals_logged > 0) ? {
  calories: yesterdayRaw.calories_consumed,
  protein: yesterdayRaw.protein_consumed_g
} : null;

// Weekly average (only if data exists)
const weeklyAvg = weeklyAvgRaw?.avg_calories ? {
  avg_calories: Math.round(weeklyAvgRaw.avg_calories),
  avg_protein: Math.round(weeklyAvgRaw.avg_protein)
} : null;

const restrictions = Array.isArray(profile.dietary_restrictions) ? profile.dietary_restrictions : [];
const allergies = Array.isArray(profile.food_allergies) ? profile.food_allergies : [];
const dislikes = Array.isArray(profile.disliked_foods) ? profile.disliked_foods : [];
const mealCount = profile.meals_per_day || profile.meal_count || 3;
const localCulture = profile.local_culture || 'colombian';
const budget = profile.budget_level || 'medium';
const wakeUpTime = profile.wake_up_time || '07:00';

let p = `Eres un nutriologo experto creando el plan de comidas de UN DIA para un usuario.\n\n`;
p += `PERFIL DEL USUARIO:\n`;
p += `- Nombre: ${profile.first_name}\n`;
p += `- Objetivo calorico diario: ${profile.caloric_target} kcal\n`;
p += `- Macros objetivo: ${profile.protein_target_g}g proteina, ${profile.carb_target_g}g carbohidratos, ${profile.fat_target_g}g grasa\n`;
p += `- Restricciones dietarias: ${restrictions.length ? restrictions.join(', ') : 'ninguna'}\n`;
p += `- Alergias: ${allergies.length ? allergies.join(', ') : 'ninguna'}\n`;
p += `- Alimentos que no le gustan: ${dislikes.length ? dislikes.join(', ') : 'ninguno'}\n`;
p += `- Cultura gastronomica: ${localCulture}\n`;
p += `- Presupuesto: ${budget}\n`;
p += `- Numero de comidas: ${mealCount}\n`;
p += `- Hora de despertar: ${wakeUpTime}\n`;
p += `- Dia: ${dayOfWeek} (${planDate})\n`;
p += `- Es fin de semana: ${isWeekend}\n`;
p += `- Tiene entrenamiento programado: ${hasWorkout}\n\n`;

if (recentMeals) {
  p += `COMIDAS DE LOS ULTIMOS 3 DIAS (no repitas estos platos):\n${recentMeals}\n`;
}
if (yesterdayIntake) {
  p += `INTAKE REAL DE AYER:\n`;
  p += `- Calorias consumidas: ${yesterdayIntake.calories} kcal (meta: ${profile.caloric_target})\n`;
  p += `- Proteina consumida: ${yesterdayIntake.protein}g (meta: ${profile.protein_target_g})\n`;
  if (yesterdayIntake.calories > profile.caloric_target + 200) {
    p += `NOTA: Ayer se excedio en calorias. Ajusta ligeramente el plan de hoy hacia la parte baja del rango.\n`;
  }
  if (yesterdayIntake.protein < profile.protein_target_g * 0.8) {
    p += `NOTA: Ayer quedo bajo en proteina. Prioriza fuentes de proteina en las comidas de hoy.\n`;
  }
  p += '\n';
}
if (weeklyAvg) {
  p += `PROMEDIO SEMANAL ACTUAL:\n`;
  p += `- Calorias promedio: ${weeklyAvg.avg_calories} kcal/dia\n`;
  p += `- Proteina promedio: ${weeklyAvg.avg_protein}g/dia\n`;
  if (weeklyAvg.avg_calories > profile.caloric_target + 100) {
    p += `NOTA: El promedio semanal esta por encima de la meta. Apunta al limite bajo del rango calorico hoy.\n`;
  }
  p += '\n';
}

p += `INSTRUCCIONES:\n`;
p += `1. Genera exactamente ${mealCount} comidas para este dia.\n`;
p += `2. Las calorias totales del dia deben estar entre ${profile.caloric_target - 50} y ${profile.caloric_target + 50}.\n`;
p += `3. Los macros deben acercarse a los objetivos (±10%).\n`;
p += `4. NUNCA incluyas alimentos de las restricciones, alergias o disgustos.\n`;
p += `5. Usa ingredientes comunes en la cultura ${localCulture}.\n`;
p += `6. Adapta al presupuesto: low=proteinas economicas (huevo, pollo, atun, leguminosas); medium=pechuga, carne molida, tilapia; high=sin restriccion.\n`;
p += `7. Distribuye las comidas desde ${wakeUpTime} con intervalos de 3-4 horas.\n`;
p += `8. Preparacion: maximo 25 minutos${isWeekend ? ' (fin de semana, puede ser mas elaborada)' : ''}.\n`;
p += `9. NO repitas platos de los ultimos 3 dias.\n`;
p += `10. Varia el tipo de proteina entre comidas del mismo dia.\n`;
if (hasWorkout) {
  p += `11. El usuario tiene entrenamiento hoy. Incluye snack pre o post-entrenamiento si el numero de comidas lo permite.\n`;
}

p += `\nFORMATO DE SALIDA — responde EXCLUSIVAMENTE con JSON valido:\n`;
p += `{"plan_date":"${planDate}","day_of_week":"${dayOfWeek}","total_calories":<n>,"total_protein_g":<n>,"total_carbs_g":<n>,"total_fat_g":<n>,"meals":[{"meal_type":"breakfast|lunch|snack|dinner","meal_label":"Desayuno|Almuerzo|Snack|Cena","time":"HH:MM","name":"<nombre en espanol>","calories":<n>,"protein_g":<n>,"carbs_g":<n>,"fat_g":<n>,"ingredients":[{"name":"<ingrediente>","quantity":"<cantidad>","grams":<n>}],"preparation_notes":"<instrucciones breves>"}]}`;

return [{ json: { prompt: p, userId, planDate, dayOfWeek } }];

const response = $('Generate Meal Plan').first().json.text || '';
let plan;

try {
  plan = JSON.parse(response);
} catch (e) {
  const jsonMatch = response.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    plan = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No se pudo parsear el plan diario generado por OpenAI');
  }
}

// Validate daily plan structure (v2)
if (!plan.meals || !Array.isArray(plan.meals)) {
  throw new Error('El plan no contiene la estructura de meals esperada');
}
if (plan.meals.length < 3) {
  throw new Error('El plan tiene menos de 3 comidas');
}

const buildData = $('Build Daily Meal Plan Prompt').first().json;
plan.plan_date = buildData.planDate;
plan.day_of_week = buildData.dayOfWeek;

const totalCalories = plan.total_calories ||
  plan.meals.reduce((sum, m) => sum + (m.calories || 0), 0);
const totalProtein = plan.total_protein_g ||
  plan.meals.reduce((sum, m) => sum + (m.protein_g || 0), 0);

return [{
  json: {
    plan,
    totalCalories: Math.round(totalCalories),
    totalProtein: Math.round(totalProtein),
    userId: buildData.userId,
    planDate: buildData.planDate
  }
}];

parameters.query:
INSERT INTO meal_plans (user_id, plan_date, plan_json, total_calories, is_active, generated_at)
VALUES ($1, $2::date, $3, $4, true, NOW())
RETURNING id;

parameters.jsCode:
const plan = $('Parse and Validate Plan').first().json.plan;
const meals = plan.meals || [];

let formatted = `Plan de comidas para ${plan.day_of_week} (${plan.plan_date}):\n\n`;
for (const meal of meals) {
  formatted += `${meal.meal_label} (${meal.time}): ${meal.name} — *${meal.calories} kcal*, ${meal.protein_g}g proteina\n`;
}
formatted += `\nTotal del dia: *${plan.total_calories} kcal* | *${plan.total_protein_g}g* proteina`;

return [{
  json: {
    formattedPlan: formatted,
    plan,
    totalCalories: plan.total_calories,
    totalProtein: plan.total_protein_g,
    planDate: plan.plan_date,
    success: true
  }
}];

